head.script:
scwin.vLoginCoCd = "";
scwin.vLoginCoClsCd = "";
scwin.vUserHomeClsCd = "";
scwin.isSubCompany = false;
scwin.user_id = "";
scwin.SUBSIDIARY_USER_HOME_CLS_CD = "SA";
scwin.CO_CD_DONGBU = "";
scwin.CO_CLS_CD_DONGBU = "0";
scwin.KOREA_WON = "KRW";
scwin.privAdmin = "F";
scwin.checkUser = false;
scwin.txtCoClsCd = "";
scwin.txtCoCd = "";
scwin.hid_recverCrnNm = "";
scwin.txt_evidClsNm = "";
scwin.closeControlResult = true;

scwin.onpageload = async function() {
    scwin.vLoginCoCd = $c.ses.getCoCd() || "";
    scwin.vLoginCoClsCd = $c.ses.getCoClsCd() || "";
    scwin.vUserHomeClsCd = $c.ses.getUserHomeClsCd() || "";
    scwin.user_id = $c.ses.getUserId() || "";
    scwin.privAdmin = $c.ses.getPrivAdmin() || "F";
    scwin.CO_CD_DONGBU = $c.ses.getCoDongbu() || "";
    scwin.CO_CLS_CD_DONGBU = $c.ses.getCoClsCdDongbu() || "0";
    scwin.KOREA_WON = "KRW";

    if (scwin.user_id == "050262" || scwin.user_id == "110722" || scwin.user_id == "090466" || scwin.user_id == "120010") {
        scwin.checkUser = true;
    }

    scwin.f_OnLoad();
};

scwin.onUdcCompleted = async function() {
    let curDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    udc_acqDt.setInitDate(curDate.substring(0, 6) + "01", curDate);
};

scwin.dataSetDebug = async function(dataList, isDebug) {
    if (isDebug == true) {
        let obj = dataList;
        let str = "[[[[" + obj.id + "]]]]]\n";
        let colIds = obj.getColumnIds();
        for (let dsRow = 0; dsRow < obj.getRowCount(); dsRow++) {
            for (let dsCol = 0; dsCol < colIds.length; dsCol++) {
                str += "[" + colIds[dsCol] + "] " + obj.getCellData(dsRow, colIds[dsCol]) + ", ";
            }
            str += "\n\n";
        }
        await $c.win.alert(str);
    }
};

scwin.f_OnLoad = async function() {
    $c.gus.cfDisableKey();

    await $c.sbm.execute(sbm_asetPattern);
    await $c.sbm.execute(sbm_evidClsCd);

    $c.gus.cfDisableObjects([tbl_evidence, ed_email]);

    scwin.f_FieldClear();
    scwin.f_setCompanyInfo();
};

scwin.f_setCompanyInfo = async function() {
    if (scwin.vUserHomeClsCd != scwin.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = scwin.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = scwin.CO_CLS_CD_DONGBU;
    }

    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo("T");

    if ("T" == scwin.privAdmin || !scwin.isSubCompany) {
        $c.gus.cfEnableObjects([ed_coCd, txt_coNm, img_company, img_initAmt]);
    } else {
        $c.gus.cfDisableObjects([ed_coCd, txt_coNm, img_company, img_initAmt]);
    }
};

scwin.f_FieldClear = async function() {
    $c.gus.cfInitObjects(tbl_search, [ica_acqDtStDt, ica_acqDtEndDt, ica_procDt]);
    scwin.f_SetSrchDefault();
};

scwin.f_SetSrchDefault = async function() {
    let curDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    ica_acqDtStDt.setValue(curDate.substring(0, 6) + "01");
    ica_acqDtEndDt.setValue(curDate);
    ica_acqDtStDt.setFocus();
};

scwin.f_Retrieve = async function() {
    if (!(await scwin.f_RetrieveValidate())) {
        return false;
    }

    gr_master.setColumnProp("procYn", "headCheck", false);
    ds_evidence.undo();
    ds_collMoney.removeAll();

    if (chk_lowerDeptIncluYn.getValue() == "1" || chk_lowerDeptIncluYn.getValue() == "true") {
        if (ed_srchAcctDeptCd.getValue() == "") {
            await $c.win.alert("하위부서포함여부 체크시에는 귀속부서를 입력해주세요.");
            ed_srchAcctDeptCd.setFocus();
            return;
        } else {
            ds_search.set("lowerDeptIncluYn", "1");
        }
    } else {
        ds_search.set("lowerDeptIncluYn", "");
    }
    await $c.sbm.execute(sbm_search);
};

scwin.f_Retrieve1 = async function() {
    if (ed_srchFixedAsetNo.getValue() == "") {
        return false;
    }

    if (ds_master.getRowCount() == 0) {
        await scwin.f_Retrieve();
        ed_srchFixedAsetNo.setValue("");
        return;
    }

    gr_master.setColumnProp("procYn", "headCheck", false);

    await $c.sbm.execute(sbm_addSearch);
};

scwin.f_OpenCalendar = async function() {
    ica_procDt.setFocus();
    scwin.f_checkProcDt();
};

scwin.f_checkProcDt = async function() {
    let input_procDt = ica_procDt.getValue();
    let output_procDt = ica_procDt.getValue();

    if (ds_master.getRowCount() > 0) {
        output_procDt = ds_master.getCellData(0, "procDt");
    }
    if (input_procDt != output_procDt) {
        await $c.win.alert("매각일자가 변경되어 재조회 됩니다.");
        scwin.f_Retrieve();
    }
};

scwin.f_RetrieveValidate = async function() {
    if ($c.gus.cfIsNull(ica_acqDtStDt.getValue()) && $c.gus.cfIsNull(ica_acqDtEndDt.getValue())
            && $c.gus.cfIsNull(acb_asetPatternCd.getValue())
            && $c.gus.cfIsNull(ed_srchAcctDeptCd.getValue()) && $c.gus.cfIsNull(txt_srchAcctDeptNm.getValue())
            && $c.gus.cfIsNull(ed_srchFixedAsetNo.getValue())) {
        await $c.gus.cfAlertMsg("조회조건을 하나 이상 입력해 주세요.");
        ica_acqDtStDt.setFocus();
        return false;
    }

    let chk = await $c.gus.cfValidate([tbl_search]);
    if (!chk) {
        return false;
    }

    if ($c.gus.cfIsNull(ica_acqDtStDt.getValue()) && !$c.gus.cfIsNull(ica_acqDtEndDt.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["취득일자"]);
        ica_acqDtStDt.setFocus();
        return false;
    }

    if (!$c.gus.cfIsNull(ica_acqDtStDt.getValue()) && $c.gus.cfIsNull(ica_acqDtEndDt.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["취득일자"]);
        ica_acqDtEndDt.setFocus();
        return false;
    }

    if (!$c.gus.cfIsNull(ica_acqDtStDt.getValue()) && !$c.gus.cfIsNull(ica_acqDtEndDt.getValue())) {
        if (!$c.gus.cfValidateValue(ica_acqDtEndDt.getValue(), "minDate=" + ica_acqDtStDt.getValue())) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
            ica_acqDtStDt.setFocus();
            return false;
        }
    }

    return true;
};

scwin.f_WholeProc = async function() {
    let temp = 0;
    for (let i = 0; i < ds_master.getRowCount(); i++) {
        if (ds_master.getCellData(i, "procYn") == "1") {
            if ((ds_master.getCellData(i, "asetPatternNm") == "토지") || (ds_master.getCellData(i, "asetPatternNm") == "건물")) {
                ds_master.setCellData(i, "procArea", ds_master.getCellData(i, "area"));
                ds_master.setCellData(i, "procAmt", ds_master.getCellData(i, "bookAmt"));
            } else {
                ds_master.setCellData(i, "procQty", ds_master.getCellData(i, "qty"));
                ds_master.setCellData(i, "procAmt", ds_master.getCellData(i, "bookAmt"));
            }
        } else {
            temp++;
        }
    }
    if (temp == ds_master.getRowCount()) {
        await $c.win.alert("선택된 행이 없습니다.");
        return;
    }
};

scwin.f_CloseControlRetrieve = async function() {
    let coCd = ed_coCd.getValue();
    let qryStdt = ica_spplyDt.getValue().substring(0, 6);
    let wrkNo = "FI05";

    // TODO: sbm_closeControl에 동적 파라미터 전달 필요
    scwin.closeControlResult = true;
    await $c.sbm.execute(sbm_closeControl);

    if (ds_closeControl.getRowCount() > 0) {
        if (ds_closeControl.getCellData(0, "closePrgsStsCd") == "0") {
            await $c.win.alert("[" + qryStdt + "] 월에 감가삼각마감이 진행중입니다.\n매각처리가 불가능합니다. 재경팀의 문의하세요.");
            scwin.closeControlResult = false;
            return false;
        }
        if (ds_closeControl.getCellData(0, "closePrgsStsCd") == "2") {
            await $c.win.alert("[" + qryStdt + "] 월에 감가삼각마감이 마감완료되었습니다.\n매각처리가 불가능합니다. 재경팀의 문의하세요.");
            scwin.closeControlResult = false;
            return false;
        } else {
            scwin.closeControlResult = true;
            return true;
        }
    } else {
        scwin.closeControlResult = true;
        return true;
    }
};

scwin.f_Save = async function() {
    // TODO: cfUploadFile 파일업로드 처리 후 uploadComplete 콜백
    scwin.uploadComplete();
};

scwin.uploadComplete = async function() {
    scwin.f_SaveProc();
};

scwin.f_SaveProc = async function() {
    if (ds_master.getUpdatedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["매각자산"]);
        return;
    } else {
        let evidFileClsCd = ds_evidence.get("evidFileClsCd");
        if (fileUploadGDS.getRowCount() > 0) {
            if (evidFileClsCd == "" || evidFileClsCd == "00") {
                await $c.win.alert("증빙파일구분을 선택하세요");
                return;
            }
        }

        if (chk_declarExceptYn.getValue() != "1" && chk_declarExceptYn.getValue() != "true") {
            if (ed_email.getValue() == "") {
                await $c.win.alert("이메일을 입력하세요");
                return;
            }
        }

        let chkProcDt = await $c.gus.cfValidate([ica_procDt]);
        if (!chkProcDt) return;

        if (!(await scwin.f_ValidateAset())) return;

        let chkEvid = await $c.gus.cfValidate([tbl_evidence]);
        if (!chkEvid) return;

        if ($c.gus.cfIsNull(ed_clntNo.getValue())) {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_018, ["거래처번호", "사업자번호 확인"]);
            ed_clntNo.setFocus();
            return;
        }

        if (!(await scwin.f_ValidateInitamt())) return;

        let rentCheck = 0;
        for (let i = 0; i < ds_master.getRowCount(); i++) {
            if (ds_master.getCellData(i, "procYn") == "1" || ds_master.getRowStatus(i) == "D") {
                if (ds_master.getCellData(i, "asetPatternCd") == "30") {
                    if (ds_master.getCellData(i, "bizDomCd") == "220") {
                        for (let j = 0; j < ds_master.getRowCount(); j++) {
                            if (ds_master.getCellData(j, "procYn") == "1" || ds_master.getRowStatus(j) == "D") {
                                if (ds_master.getCellData(j, "bizDomCd") != "220") {
                                    rentCheck++;
                                }
                            }
                        }
                    }
                }
            }
        }

        if (rentCheck > 0) {
            await $c.win.alert("렌터차량 매각은 사업영역이 렌터차량인 차량만 가능합니다.");
            return;
        }

        let chkDeptCd = "";
        let chkRow = 0;
        let chkDeptNm = "";
        if (scwin.vUserHomeClsCd != scwin.SUBSIDIARY_USER_HOME_CLS_CD) {
            for (let i = 0; i < ds_master.getRowCount(); i++) {
                if (ds_master.getCellData(i, "procYn") == "1") {
                    if (chkDeptCd == "") {
                        chkRow = i;
                        chkDeptCd = ds_master.getCellData(i, "acctDeptCd");
                        chkDeptNm = ds_master.getCellData(i, "acctDeptNm");
                    } else {
                        if (chkDeptCd != ds_master.getCellData(i, "acctDeptCd")) {
                            await $c.win.alert("자산의 귀속부서가 서로 다른 자산들은 매각처리가 불가능합니다.(" + (chkRow + 1) + "행:" + chkDeptNm + "," + (i + 1) + "행:" + ds_master.getCellData(i, "acctDeptNm") + ")");
                            ds_master.setRowPosition(i);
                            return;
                        }
                    }
                }
            }
        }

        if (!(await scwin.f_CloseControlRetrieve())) {
            return;
        }

        let confirmResult = await $c.gus.cfConfirmMsg(MSG_CM_CRM_001);
        if (confirmResult) {
            for (let i = 0; i < ds_master.getRowCount(); i++) {
                if (ds_master.getCellData(i, "procYn") == "1" || ds_master.getRowStatus(i) == "D") {
                    ds_master.setCellData(i, "procDt", ica_procDt.getValue());
                }
            }
            ds_evidence.set("coCd", ed_coCd.getValue());
            ds_evidence.set("coClsCd", scwin.txtCoClsCd);
            await $c.sbm.execute(sbm_master);
        }
    }
};

scwin.f_ValidateAset = async function() {
    for (let i = 0; i < ds_master.getRowCount(); i++) {
        if (ds_master.getCellData(i, "procYn") == "1" || ds_master.getRowStatus(i) == "D") {
            if (parseFloat(ds_master.getCellData(i, "procQty")) <= 0) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["매각수량"]);
                gr_master.setFocusedCell(i, "procQty");
                return false;
            }
            if (parseFloat(ds_master.getCellData(i, "procQty")) > parseFloat(ds_master.getCellData(i, "qty"))) {
                await $c.gus.cfAlertMsg("매각수량이 수량을 초과하였습니다.");
                gr_master.setFocusedCell(i, "procQty");
                return false;
            }

            if (parseFloat(ds_master.getCellData(i, "procAmt")) <= 0) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["매각액"]);
                gr_master.setFocusedCell(i, "procQty");
                return false;
            }

            if (ds_master.getCellData(i, "procRate") == "100") {
                if (ds_master.getCellData(i, "procQty") != ds_master.getCellData(i, "qty")) {
                    await $c.gus.cfAlertMsg("매각비율이 100(%)인경우 수량과 매각수량은 일치해야합니다.");
                    gr_master.setFocusedCell(i, "procQty");
                    return false;
                }
            }
        }
    }
    return true;
};

scwin.f_ValidateInitamt = async function() {
    let initAmt = parseFloat(ds_evidence.get("initamt")) || 0;
    let settleAmtSum = scwin.f_GetSettleAmt();

    if (initAmt < 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_057, ["선수금액", "0"]);
        ed_initamt.setFocus();
        return false;
    }

    if (initAmt != settleAmtSum) {
        await $c.gus.cfAlertMsg("입력한 선수금 금액과 정리금액이 다릅니다.\n\n정리금액 = " + $c.gus.cfInsertComma(settleAmtSum));
        ed_initamt.setFocus();
        return false;
    }

    let refundAmt = parseInt(ed_spplyAmt.getValue().trim() || "0") + parseInt(ed_vat.getValue().trim() || "0") - parseInt(initAmt);
    if (refundAmt < 0) {
        await $c.gus.cfAlertMsg("미수금은 0보다 작을 수 없습니다.\n\n미수금 = " + refundAmt);
        gr_master.setFocusedCell(ds_master.getRowPosition(), "procAmt");
        return false;
    }

    return true;
};

scwin.f_GetSettleAmt = async function() {
    let settleAmtSum = 0;

    if (ds_collMoney.getRowCount() > 0) {
        for (let i = 0; i < ds_collMoney.getRowCount(); i++) {
            settleAmtSum += parseFloat(ds_collMoney.getCellData(i, "remainAmt")) || 0;
        }
    }
    return settleAmtSum;
};

scwin.f_GetObjValue = async function(inObj) {
    if (inObj && typeof inObj.getValue === "function") {
        return inObj.getValue();
    }
    return "";
};

scwin.f_SetObjValue = async function(inObj, val) {
    if (inObj && typeof inObj.setValue === "function") {
        inObj.setValue(val);
    }
};

scwin.f_PopUp = async function(codeObj, nameObj, sQueryID, sWhere, sWidth) {
    let rtnList = $c.gus.cfCommonPopUp(sQueryID, scwin.f_GetObjValue(codeObj), ""
                                , scwin.f_EventCheck(), null, null, null, null
                                , sWhere, sWidth, null, null, null);

    if (rtnList != null) {
        if (rtnList[0] != "N/A") {
            scwin.f_SetObjValue(codeObj, rtnList[0]);
            scwin.f_SetObjValue(nameObj, rtnList[1]);
        }
    } else {
        scwin.f_SetObjValue(codeObj, "");
        scwin.f_SetObjValue(nameObj, "");
    }

    return rtnList;
};

scwin.f_GridPopUp = async function(inValue, sIsEvent, sQueryID, sWhere, sWidth) {
    let rtnList = $c.gus.cfCommonPopUp(sQueryID, inValue, ""
                                , sIsEvent, null, null, null, null
                                , sWhere, sWidth, null, null, null);

    return rtnList;
};

scwin.f_IsPopUp = async function() {
    let inObj = arguments[0];
    let inValue = scwin.f_GetObjValue(inObj);

    if ($c.gus.cfIsNull(inValue)) {
        for (let i = 1; i < arguments.length; i++) {
            scwin.f_SetObjValue(arguments[i], "");
        }
        return false;
    }

    return true;
};

scwin.f_EventCheck = async function() {
    return "F";
};

scwin.f_srchDeptPopUp = async function() {
    let param = "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd;
    let rtnList = scwin.f_PopUp(ed_srchAcctDeptCd, txt_srchAcctDeptNm, "retrieveAcctDeptCdInfo6", param, "410");
};

scwin.f_crnPopUp = async function() {
    let selectID = "retrieveCrnInfo";
    let param = "";

    if (scwin.isSubCompany) {
        selectID = "retrieveCrnClntInfo";
        param = "," + ed_coCd.getValue();
    }
    let rtnList = scwin.f_PopUp(ed_recverCrn, { setValue: function(v) { scwin.hid_recverCrnNm = v; }, getValue: function() { return scwin.hid_recverCrnNm; } }, selectID, param, null);
    if (rtnList != null) {
        if (rtnList[0] != "" && rtnList[0] != "N/A") {
            // TODO: sbm_clntNo에 동적 파라미터 전달 필요
            await $c.sbm.execute(sbm_clntNo);
        }
    }
};

scwin.f_checkPopEd = async function(strCdObj, strNmObj, flag) {
    if (strCdObj.getValue() == "") {
        if (strNmObj.getValue().trim() != "") {
            scwin.f_openPopUp(flag, "T");
        }
    } else {
        strNmObj.setValue("");
        if (strCdObj.getValue().trim() != "") {
            scwin.f_openPopUp(flag, "T");
        }
    }
};

scwin.f_resultPopEd = async function(strCdObj, strNmObj, strCrnObj, rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") {
            return;
        }
        strCdObj.setValue(rtnList[0]);
        strNmObj.setValue(rtnList[1]);
        strCrnObj.setValue(rtnList[4]);
    } else {
        strCdObj.setValue("");
        strNmObj.setValue("");
        strCrnObj.setValue("");
    }
};

scwin.f_vatDeclarDeptPopUp = async function() {
    let param = ",,," + ed_coCd.getValue() + "," + scwin.txtCoClsCd + "," + ica_spplyDt.getValue().substring(0, 4);

    let rtnList = $c.gus.cfCommonPopUp("retrieveVatDeclarAcctDeptCd"
                                , ed_vatDeclarAcctDeptCd.getValue()
                                , ""
                                , scwin.f_EventCheck()
                                , null
                                , null
                                , null
                                , null
                                , param
                                , "410"
                                , null
                                , null
                                , null
    );

    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        scwin.f_SetObjValue(ed_vatDeclarAcctDeptCd, rtnList[2]);
        scwin.f_SetObjValue(txt_vatDeclarAcctDeptNm, rtnList[3]);
        scwin.f_SetObjValue(ed_vatSpplierCrn, rtnList[5]);
    } else {
        scwin.f_SetObjValue(ed_vatDeclarAcctDeptCd, "");
        scwin.f_SetObjValue(txt_vatDeclarAcctDeptNm, "");
        scwin.f_SetObjValue(ed_vatSpplierCrn, "");
    }
};

scwin.f_CheckComboData = async function(objCombo, comboTitle) {
    if (objCombo.getSelectedIndex() == -1 && $c.gus.cfIsNull(objCombo.getValue()) == false) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_038, [comboTitle + "코드"]);
        objCombo.setFocus();
    }
};

scwin.f_initAmtPopUp = async function() {
    let sUrl = "/ui/ac/fm/collmoneymgnt/rcptmgnt/fm_502_03_00p.xml";
    let valueObject = {};
    valueObject.prov = ds_collMoney;

    if (ica_procDt.getValue() == "") {
        valueObject.fromDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    } else {
        valueObject.fromDate = $c.date.addMonth(ica_procDt.getValue(), -1);
    }

    valueObject.toDate = ica_procDt.getValue();
    valueObject.clsCd = "2";

    let returnValue = await $c.win.openPopup(sUrl, {
        width: 825,
        height: 560,
        modal: true,
        data: valueObject
    });
    ed_initamt.setValue(scwin.f_GetSettleAmt());
};

scwin.f_PopUpCompanyInfo = async function(pWinCloseTF) {
    let rtnList = $c.gus.cfCommonPopUp("retrieveDongbuGroupCompanyInfo"
                                , ed_coCd.getValue()
                                , txt_coNm.getValue()
                                , pWinCloseTF
                                , null
                                , null
                                , null
                                , null
                                , null
                                , null
                                , null
                                , null
                                , null
    );

    if (rtnList != null) {
        if (rtnList[0] == "N/A") {
            return;
        }
        ed_coCd.setValue(rtnList[0]);
        txt_coNm.setValue(rtnList[5]);
        scwin.txtCoClsCd = rtnList[1];

        $c.gus.cfInitObjects([ed_srchAcctDeptCd, txt_srchAcctDeptNm]);
    } else {
        ed_coCd.setValue("");
        txt_coNm.setValue("");
        scwin.txtCoClsCd = "";
    }

    if (scwin.txtCoClsCd > scwin.CO_CLS_CD_DONGBU) {
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }
};

scwin.f_openPopUp = async function(flag, check, isCdYn) {
    let rtnList = [];
    switch (flag) {
        case "1":
            let where = "";
            rtnList = $c.gus.cfCommonPopUp("retrieveClntEmail", ed_clntNo.getValue().trim(), ed_email.getValue().trim(), check, null, null, null, null, where, null, null, null, null);
            if (rtnList != null) {
                if (rtnList[0] == "N/A") {
                    return;
                }
                ed_email.setValue(rtnList[0]);
            } else {
                ed_email.setValue("");
            }
            break;

        case "10":
            let param = ",,," + ed_coCd.getValue();

            rtnList = $c.gus.cfCommonPopUp("retrieveClntList", ed_clntNo.getValue().trim(), txt_clntNm.getValue(), check, null, null, null, null, param, null, null, null, null);
            scwin.f_resultPopEd(ed_clntNo, txt_clntNm, ed_recverCrn, rtnList);
            break;

        default:
            break;
    }
};

