};

scwin.f_EvidClsCd = async function() {
    if (acb_evidClsCd.getValue() == "20") {
        $c.gus.cfEnableObjects([acb_zeroTaxCls]);
        acb_zeroTaxCls.setSelectedIndex(1);
        ed_vat.setValue("0");
        $c.gus.cfDisableObjects([ed_vat]);
    } else {
        acb_zeroTaxCls.setSelectedIndex(-1);
        $c.gus.cfDisableObjects([acb_zeroTaxCls]);
        $c.gus.cfEnableObjects([ed_vat]);

        ed_vat.setValue(Math.round(parseFloat(ed_spplyAmt.getValue().trim() || "0") * 0.1));
    }

    if (ds_master.getCellData(ds_master.getRowPosition(), "procYn") == "1") {
        ed_spplyAmt.setValue(ds_master.getCellData(ds_master.getRowPosition(), "procAmt"));
    }
};

scwin.sbm_search_submitdone = async function(e) {
    let rowCnt = ds_master.getRowCount();
    totalRows.setValue(rowCnt);

    if (rowCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        $c.gus.cfDisableObjects([tbl_evidence]);

        acb_evidClsCd.setSelectedIndex(-1);
        acb_deductClsCd.setSelectedIndex(-1);
    } else {
        scwin.f_EvidHeaderCreate();
        $c.gus.cfEnableObjects([tbl_evidence]);
        $c.gus.cfDisableKey();
        gr_master.setFocus();

        $c.gus.cfDisableObjects([ed_email]);

        acb_evidClsCd.setValue("10");
        scwin.f_EvidClsCd();
        acb_deductClsCd.setValue("1");
    }
};

