scwin.sbm_addSearch_submitdone = async function(e) {
    let rowCnt = ds_master_temp.getRowCount();

    if (rowCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    } else {
        for (let i = 0; i < ds_master_temp.getRowCount(); i++) {
            let newRow = ds_master.insertRow();
            let colIds = ds_master_temp.getColumnIds();
            for (let c = 0; c < colIds.length; c++) {
                ds_master.setCellData(newRow, colIds[c], ds_master_temp.getCellData(i, colIds[c]));
            }
        }
        ed_srchFixedAsetNo.setValue("");
    }
};

