scwin.ds_master_onrowpositionchange = async function(rowIndex, oldRow) {
    let row = rowIndex;
    if (row < 0) return;

    if (ds_master.getCellData(row, "procYn") == "1") {
        if (parseFloat(ds_master.getCellData(row, "qty")) == 1) {
            gr_master.setColumnProp("procQty", "readOnly", false);
            gr_master.setColumnProp("procRate", "readOnly", false);
        } else {
            gr_master.setColumnProp("procQty", "readOnly", false);
            gr_master.setColumnProp("procRate", "readOnly", false);
        }
        gr_master.setColumnProp("procAmt", "readOnly", false);
        gr_master.setColumnProp("reappraiseAmt", "readOnly", false);
        gr_master.setColumnProp("procArea", "readOnly", false);
    } else {
        gr_master.setColumnProp("procQty", "readOnly", true);
        gr_master.setColumnProp("procAmt", "readOnly", true);
        gr_master.setColumnProp("procRate", "readOnly", true);
        gr_master.setColumnProp("reappraiseAmt", "readOnly", true);
        gr_master.setColumnProp("procArea", "readOnly", true);
    }
};

scwin.ds_master_oncelldatachange = async function(info) {
    let row = info.row;
    let colid = info.colId;

    if (colid == "procYn" && ds_master.getCellData(row, "procYn") == "0") {
        ds_master.setCellData(row, "procQty", 0);
        ds_master.setCellData(row, "procAmt", 0);
        ds_master.setCellData(row, "procAcqAmt", 0);
        ds_master.setCellData(row, "procRate", 0);
        ds_master.setCellData(row, "procBefYyProvAmt", 0);
        ds_master.setCellData(row, "procThisYyProvAmt", 0);
        ds_master.setCellData(row, "procBookAmt", 0);
        ds_master.setCellData(row, "procDifferAmt", 0);
        ds_master.setCellData(row, "reappraiseAmt", 0);
        return;
    }
    if (colid == "procYn" && ds_master.getCellData(row, "procYn") == "1" && ds_master.getCellData(row, "lentYn") == "1") {
        ds_master.setCellData(row, "procYn", "0");
        await $c.gus.cfAlertMsg("임대중인 자산은 처리할 수 없습니다.");
        return;
    }

    if ((ds_master.getCellData(row, "asetPatternNm") == "토지") || (ds_master.getCellData(row, "asetPatternNm") == "건물")) {
        if (colid == "procArea") {
            ds_master.setCellData(row, "procRate", (parseFloat(ds_master.getCellData(row, "procArea")) / parseFloat(ds_master.getCellData(row, "area"))) * 100);
            let procRate = parseFloat(ds_master.getCellData(row, "procRate")) / 100;
            ds_master.setCellData(row, "procQty", parseFloat(ds_master.getCellData(row, "qty")) * procRate);
        }
    } else {
        if (colid == "procQty") {
            ds_master.setCellData(row, "procRate", (parseFloat(ds_master.getCellData(row, "procQty")) / parseFloat(ds_master.getCellData(row, "qty"))) * 100);
            let procRate = parseFloat(ds_master.getCellData(row, "procRate")) / 100;
        }
    }

    if (colid == "procRate" && parseFloat(ds_master.getCellData(row, "qty")) == 1) {
        ds_master.setCellData(row, "procQty", (parseFloat(ds_master.getCellData(row, "procRate")) * parseFloat(ds_master.getCellData(row, "qty"))) / 100);
        let procQty = parseFloat(ds_master.getCellData(row, "procQty"));
    }

    if (colid == "procRate") {
        let procRate = parseFloat(ds_master.getCellData(row, "procRate")) / 100;
        ds_master.setCellData(row, "procAcqAmt", Math.round(parseFloat(ds_master.getCellData(row, "acqAmt")) * procRate));

        ds_master.setCellData(row, "procBefYyProvAmt", Math.round(parseFloat(ds_master.getCellData(row, "befYyProvAmt")) * procRate));
        ds_master.setCellData(row, "procThisYyProvAmt", Math.round(parseFloat(ds_master.getCellData(row, "thisYyProvAmt")) * procRate));
        ds_master.setCellData(row, "procBookAmt", parseFloat(ds_master.getCellData(row, "procAcqAmt"))
                - (parseFloat(ds_master.getCellData(row, "procBefYyProvAmt")) + parseFloat(ds_master.getCellData(row, "procThisYyProvAmt"))));
        ds_master.setCellData(row, "procDifferAmt", Math.round(parseFloat(ds_master.getCellData(row, "procAmt")) - parseFloat(ds_master.getCellData(row, "procBookAmt"))));

        let spplyAmtSum = 0;
        for (let si = 0; si < ds_master.getRowCount(); si++) {
            spplyAmtSum += parseFloat(ds_master.getCellData(si, "procAmt")) || 0;
        }
        ed_spplyAmt.setValue(spplyAmtSum);
        ed_vat.setValue(Math.round(parseFloat(ed_spplyAmt.getValue().trim() || "0") * 0.1));

        if (ds_master.getCellData(row, "CrcCd") != scwin.KOREA_WON) {
            if (parseFloat(ds_master.getCellData(row, colid)) != 100 && parseFloat(ds_master.getCellData(row, colid)) != 0) {
                await $c.win.alert("외화 자산의 경우 부분매각을 할 수 없습니다.");
                ds_master.setCellData(row, colid, 0);
            }
        }

        if (colid == "procQty") {
            if (ds_master.getCellData(row, "CrcCd") != scwin.KOREA_WON) {
                if (parseFloat(ds_master.getCellData(row, colid)) != parseFloat(ds_master.getCellData(row, "qty")) && parseFloat(ds_master.getCellData(row, colid)) != 0) {
                    await $c.win.alert("외화 자산의 경우 부분매각을 할 수 없습니다.");
                    ds_master.setCellData(row, colid, 0);
                }
            }
        }
    }

    if (colid == "procAmt") {
        ds_master.setCellData(row, "procDifferAmt", parseFloat(ds_master.getCellData(row, "procAmt")) - parseFloat(ds_master.getCellData(row, "procBookAmt")));
        let spplyAmtSum2 = 0;
        for (let si2 = 0; si2 < ds_master.getRowCount(); si2++) {
            spplyAmtSum2 += parseFloat(ds_master.getCellData(si2, "procAmt")) || 0;
        }
        ed_spplyAmt.setValue(spplyAmtSum2);
        ed_vat.setValue(Math.round(parseFloat(ed_spplyAmt.getValue().trim() || "0") * 0.1));
    }
};

scwin.gr_master_oncellclick = async function(rowIndex, columnIndex, columnId) {
    let row = rowIndex;
    let colid = columnId;

    if ((ds_master.getCellData(row, "asetPatternNm") == "토지") || (ds_master.getCellData(row, "asetPatternNm") == "건물")) {
        if (colid == "procQty" || colid == "procRate") {
            gr_master.setColumnProp(colid, "readOnly", true);
        }

        if (colid == "procAmt" || colid == "procArea" || colid == "reappraiseAmt") {
            if (ds_master.getCellData(row, "procYn") == "1") {
                gr_master.setColumnProp(colid, "readOnly", false);
            } else {
                gr_master.setColumnProp(colid, "readOnly", true);
                ds_master.setCellData(row, "procQty", 0);
                ds_master.setCellData(row, "procAmt", 0);
                ds_master.setCellData(row, "procRate", 0);
                ds_master.setCellData(row, "reappraiseAmt", 0);
                ds_master.setCellData(row, "procArea", 0);
            }
        }
    } else {
        if (colid == "procArea") {
            gr_master.setColumnProp(colid, "readOnly", true);
        }

        if (colid == "procQty" || colid == "procAmt" || colid == "procRate" || colid == "reappraiseAmt") {
            if (ds_master.getCellData(row, "procYn") == "1") {
                gr_master.setColumnProp(colid, "readOnly", false);
            } else {
                gr_master.setColumnProp(colid, "readOnly", true);
                ds_master.setCellData(row, "procQty", 0);
                ds_master.setCellData(row, "procAmt", 0);
                ds_master.setCellData(row, "procRate", 0);
                ds_master.setCellData(row, "reappraiseAmt", 0);
                ds_master.setCellData(row, "procArea", 0);
            }
        }
    }
};

